parameters.inputSchema:
{
	"type": "object",
	"properties": {
		"answer": {
			"type": "string",
			"description": "Natural language answer to user query"
		},
		"area_resolved": {
			"type": "object",
			"properties": {
				"name": {"type": "string"},
				"lat": {"type": "number"},
				"lng": {"type": "number"},
				"bbox": {"type": "array", "items": {"type": "number"}}
			},
			"description": "Resolved geographic area with coordinates"
		},
		"key_metrics": {
			"type": "object",
			"description": "Primary pollution/air quality metrics relevant to query"
		},
		"source_list": {
			"type": "array",
			"items": {"type": "string"},
			"description": "List of data sources used (API names, sensor networks, etc.)"
		},
		"data_timestamp": {
			"type": "string",
			"description": "ISO timestamp of data freshness"
		},
		"confidence": {
			"type": "string",
			"enum": ["high", "medium", "low"],
			"description": "Confidence level in answer accuracy"
		}
	},
	"required": ["answer", "source_list", "data_timestamp", "confidence"]
}

parameters.jsCode:
const chatInput = $input.item.json.chatInput || '';
const maxLength = 2000;
const outOfDomainKeywords = ['weather forecast', 'stock price', 'sports score', 'movie recommendation', 'recipe', 'translate', 'math homework'];

// Check prompt length
if (chatInput.length > maxLength) {
  return [{
    json: {
      error: 'prompt_too_long',
      message: 'Your message is too long. Please keep it under 2000 characters.',
      reject: true
    }
  }];
}

// Check for out-of-domain queries
const lowerInput = chatInput.toLowerCase();
const isOutOfDomain = outOfDomainKeywords.some(keyword => lowerInput.includes(keyword));

if (isOutOfDomain) {
  return [{
    json: {
      error: 'out_of_domain',
      message: 'I can only help with air quality and pollution data for Bangladesh. Please ask about pollution levels, factories, or waterways.',
      reject: true
    }
  }];
}

// Pass through if valid
return $input.all();

const body = $input.item.json.body || {};
const allowedTypes = ['image/jpeg', 'image/png', 'image/webp'];
const maxSize = 10 * 1024 * 1024; // 10MB

// Check if image data exists
if (!body.image && !$input.item.binary.data) {
  return [{
    json: {
      error: 'missing_image',
      message: 'No image provided. Please upload an image file.',
      valid: false
    }
  }];
}

// Check file type if provided
if (body.mimeType && !allowedTypes.includes(body.mimeType)) {
  return [{
    json: {
      error: 'invalid_type',
      message: 'Invalid image type. Only JPEG, PNG, and WebP are supported.',
      valid: false
    }
  }];
}

// Check file size if provided
if (body.size && body.size > maxSize) {
  return [{
    json: {
      error: 'file_too_large',
      message: 'Image file is too large. Maximum size is 10MB.',
      valid: false
    }
  }];
}

// Pass through if valid
return [{
  json: {
    ...body,
    valid: true
  }
}];

const analysis = $input.item.json.message?.content || $input.item.json.text || '';
const prohibitedClaims = [
  'real-time sentinel',
  'live satellite',
  'thermal tracking',
  'infrared detection',
  'satellite imagery analysis'
];

const lowerAnalysis = analysis.toLowerCase();
const hasProhibitedClaim = prohibitedClaims.some(claim => lowerAnalysis.includes(claim));

if (hasProhibitedClaim) {
  return [{
    json: {
      analysis: analysis,
      warning: 'Analysis contains prohibited claims about real-time satellite capabilities',
      filtered: true,
      result: 'This analysis is based on visual inspection only. DhakaWatch does not provide real-time satellite imagery or thermal tracking.'
    }
  }];
}

return [{
  json: {
    analysis: analysis,
    filtered: false
  }
}];

const body = $input.item.json.body || {};
const reportType = body.reportType || 'summary';
const area = body.area || 'Dhaka';
const dateRange = body.dateRange || 'last_30_days';

return [{
  json: {
    reportType,
    area,
    dateRange,
    timestamp: new Date().toISOString()
  }
}];

const error = $input.item.json.error || {};
const execution = $input.item.json.execution || {};
const workflow = $input.item.json.workflow || {};

const errorMessage = error.message || 'Unknown error';
const nodeName = error.node?.name || 'Unknown node';
const workflowName = workflow.name || 'Unknown workflow';
const executionId = execution.id || 'Unknown';
const timestamp = new Date().toISOString();

const alertText = `🚨 *DhakaWatch Workflow Error*\n\n*Workflow:* ${workflowName}\n*Node:* ${nodeName}\n*Error:* ${errorMessage}\n*Execution ID:* ${executionId}\n*Time:* ${timestamp}\n\nPlease investigate immediately.`;

return [{
  json: {
    alertText,
    workflowName,
    nodeName,
    errorMessage,
    executionId,
    timestamp
  }
}];
